{
  "query": "query GetUser($uuid: ID!) { users { user(uuid: $uuid) { uuid email name isActive profile { jobTitle bio role credits subscriptionPlan } } } }",
  "variables": { "uuid": "{{userId}}" }
}

{
  "query": "query ListUsers($limit: Int, $offset: Int) { users { users(limit: $limit, offset: $offset) { uuid email name isActive createdAt } } }",
  "variables": { "limit": 100, "offset": 0 }
}

{
  "query": "query GetUserStats { users { userStats { totalUsers activeUsers inactiveUsers usersByRole { role count } usersBySubscription { subscriptionPlan count } } } }",
  "variables": {}
}

{
  "query": "mutation UpdateProfile($input: UpdateProfileInput!) { users { updateProfile(input: $input) { userId jobTitle bio timezone role credits } } }",
  "variables": { "input": { "jobTitle": "Senior Engineer", "bio": "Developer", "timezone": "America/New_York" } }
}

{
  "query": "mutation UploadAvatar($input: UploadAvatarInput!) { users { uploadAvatar(input: $input) { userId avatarUrl role credits } } }",
  "variables": { "input": { "fileData": "https://upload.wikimedia.org/wikipedia/commons/9/99/Sample_User_Icon.png" } }
}

{
  "query": "mutation UpdateUser($input: UpdateUserInput!) { users { updateUser(input: $input) { uuid email name } } }",
  "variables": { "input": { "name": "Updated Name" } }
}

{
  "query": "mutation PromoteToAdmin($input: PromoteToAdminInput!) { users { promoteToAdmin(input: $input) { uuid email profile { role } } } }",
  "variables": { "input": { "userId": "{{userId}}" } }
}

{
  "query": "mutation PromoteToSuperAdmin($input: PromoteToSuperAdminInput!) { users { promoteToSuperAdmin(input: $input) { uuid email profile { role } } } }",
  "variables": { "input": { "userId": "{{userId}}" } }
}
